  ('investigation-d5dfc642-moex-00012', 'investigation-d5dfc642', 'investigation-d5dfc642-moex-114-44c4f898', 'sub-investigation-d5dfc642-04', NULL, 'single_choice', '有關修憲程序，下列敘述何者正確？', '["修憲程序是否採記名投票，應由修憲機關依議事自律原則自行決定", "基於秘密投票原則，修憲程序應採無記名投票", "修憲程序應採記名投票，始符合正當修憲程序之要求", "僅在涉及基本國策之修改時，修憲程序始應採記名投票"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:49+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "410", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "investigation", "civil_category": "法律實務組"}'::jsonb, NULL),
  ('investigation-d5dfc642-moex-00013', 'investigation-d5dfc642', 'investigation-d5dfc642-moex-114-44c4f898', 'sub-investigation-d5dfc642-04', NULL, 'single_choice', '依憲法法庭判決，對於大學教師評鑑規定之合憲性審查，應採何等審查標準？', '["因涉及大學教師職業執行自由之限制，應採寬鬆之審查標準", "因涉及大學教師職業選擇自由之主觀條件限制，攸關大學教師人格發展 ，應採較為嚴格之審查標準", "雖涉及大學教師職業選擇自由之主觀條件限制，但基於對大學自治之尊重，應採寬鬆之審查標準", "因涉及大學教師職業選擇自由之客觀條件限制，對於大學教師權益有重大影響，應採最為嚴格之審 查標準"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:49+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "410", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "法律實務組"}'::jsonb, NULL),
